module parallel2serial
(
    input clk,
    input rst_n,
    input [3:0] d,
    output reg valid_out,
    output dout
);

reg [3:0] shift_reg;
reg [2:0] counter;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        shift_reg <= 4'b0000;
        counter <= 3'b000;
        valid_out <= 1'b0;
    end
    else begin
        if (counter == 3'b011) begin
            shift_reg <= d;
            counter <= 3'b000;
            valid_out <= 1'b1;
        end
        else begin
            counter <= counter + 1;
            shift_reg <= {shift_reg[2:0], shift_reg[3]};
            valid_out <= 1'b0;
        end
    end
end

assign dout = shift_reg[3];

endmodule
